import{c as e,Q as t,j as n,m as r}from"./chunks/framework.DpF7k2f3.js";const m=JSON.parse('{"title":"第10章 LlamaIndexとベクトルデータベース","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ja/part3-practice/chapter10.md","filePath":"ja/part3-practice/chapter10.md"}'),o={name:"ja/part3-practice/chapter10.md"};function l(i,a,p,s,c,d){return t(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="第10章-llamaindexとベクトルデータベース" tabindex="-1">第10章 LlamaIndexとベクトルデータベース <a class="header-anchor" href="#第10章-llamaindexとベクトルデータベース" aria-label="Permalink to &quot;第10章 LlamaIndexとベクトルデータベース&quot;">​</a></h1><h2 id="本章で学べること" tabindex="-1">本章で学べること <a class="header-anchor" href="#本章で学べること" aria-label="Permalink to &quot;本章で学べること&quot;">​</a></h2><p>前一章我们学了LangChain，这家伙擅长的是<strong>把各种组件串起来</strong>——搭Agent、调工具、编排复杂流程。</p><p>でも你有没有发现一个问题：LangChain虽然能做RAG，但在<strong>数据处理和索引</strong>这块，其实挺薄弱的。文档怎么切、怎么高效存储、怎么精准检索——LangChain做起来总有点力不从心。</p><p>これがLlamaIndexの专场です。</p><p>LangChainが「流程编排大师」なら、LlamaIndexは「数据索引专家」。その核心理念は：<strong>让你的私有数据能被大模型高效查询</strong>。</p><p>读完这章你会带走：</p><ul><li>LlamaIndexのコアアーキテクチャと設計思想（LangChainとの分業）</li><li><strong>高度索引タイプの詳解</strong>：Summary Index、Keyword Table Index、Knowledge Graph Indexの選択策略</li><li><strong>LlamaIndexとLangChainの協調</strong>：各自优势边界とハイブリッドアーキテクチャ実践</li><li>ベクトルデータベースの選定戦略：Chroma / Qdrant / Milvus / Pineconeそれぞれの適用シナリオ</li><li><strong>自建 vs クラウドサービス</strong>のコストと運用の对比</li></ul><hr><blockquote><p><strong>全文の翻訳は後日公開予定、しばらくお待ちください。中文版は今すぐ読めます。</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part3-practice/chapter10.html">中文版阅读</a></p></blockquote>',10)])])}const g=e(o,[["render",l]]);export{m as __pageData,g as default};
